                        case 0x04u: bytes_per_row = 40u; line_height = 8u;  text_mode = 1u; text_cols = 40u; break;
                        case 0x05u: bytes_per_row = 40u; line_height = 16u; text_mode = 1u; text_cols = 40u; break;
                        case 0x06u: bytes_per_row = 20u; line_height = 8u;  text_mode = 1u; text_cols = 20u; break;
                        case 0x07u: bytes_per_row = 20u; line_height = 16u; text_mode = 1u; text_cols = 20u; break;
