                        case 0x0Bu: bytes_per_row = 20u; line_height = 2u; break;
                        case 0x0Cu: bytes_per_row = 20u; line_height = 1u; break;
                        case 0x0Du: bytes_per_row = 20u; line_height = 2u; break;
                        case 0x0Eu: bytes_per_row = 20u; line_height = 1u; break;
                        case 0x0Fu: bytes_per_row = 40u; line_height = 1u; break;
