/* LDA_INDY - data_transfer */
static void inst_LDA_INDY(CPUState *cpu, DecodedInstruction *inst) {
    uint8_t lo = mos6502_read_byte(cpu, (uint16_t)inst->zp);
    uint8_t hi = mos6502_read_byte(cpu, (uint16_t)((uint8_t)(inst->zp + 1u)));
    uint16_t addr = (uint16_t)(((uint16_t)hi << 8) | (uint16_t)lo);
    addr = (uint16_t)(addr + (uint16_t)cpu->registers[REG_Y]);
    cpu->registers[REG_A] = mos6502_read_byte(cpu, addr);
    cpu->flags.Z = (cpu->registers[REG_A] == 0);
    cpu->flags.N = ((cpu->registers[REG_A] & 0x80u) != 0u);
}

