/* DCP_ZP_UD - arithmetic */
static void inst_DCP_ZP_UD(CPUState *cpu, DecodedInstruction *inst) {
    uint8_t m = mos6502_read_byte(cpu, inst->zp);
    m = (uint8_t)(m - 1u);
    mos6502_write_byte(cpu, inst->zp, m);
    uint8_t a = cpu->registers[REG_A];
    uint16_t diff = (uint16_t)a - (uint16_t)m;
    cpu->flags.C = (a >= m);
    cpu->flags.Z = (((uint8_t)diff) == 0u);
    cpu->flags.N = ((((uint8_t)diff) & 0x80u) != 0u);
}

