        comp->pia_orb = 0xFFu;
        comp->pia_ddra = 0x00u;
        comp->pia_ddrb = 0x00u;
        comp->pia_cra = 0x00u;
        comp->pia_crb = 0x00u;
        comp->portb = (uint8_t)((comp->pia_orb & comp->pia_ddrb) | (uint8_t)(~comp->pia_ddrb));
        comp->keyboard_code = 0xFFu;
        comp->keyboard_atascii = 0xFFu;
        comp->keyboard_sticky = 0u;
